import{_ as o,o as a,c as r,ag as t}from"./chunks/framework.BPmc_f4o.js";const u=JSON.parse('{"title":"WordPress Mode","description":"","frontmatter":{},"headers":[],"relativePath":"wordpress-mode/wordpress-mode.md","filePath":"wordpress-mode/wordpress-mode.md"}'),i={name:"wordpress-mode/wordpress-mode.md"};function l(s,e,n,d,c,p){return a(),r("div",null,[...e[0]||(e[0]=[t('<p><span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#1565c0;color:#fff;font-size:11px;font-weight:600;">PRO</span></p><h1 id="wordpress-mode" tabindex="-1">WordPress Mode <a class="header-anchor" href="#wordpress-mode" aria-label="Permalink to &quot;WordPress Mode&quot;">​</a></h1><p>WordPress Mode is a Pro panel for headless-first deployments. It combines lockdown controls and recovery tooling in one place.</p><hr><h2 id="main-controls" tabindex="-1">Main Controls <a class="header-anchor" href="#main-controls" aria-label="Permalink to &quot;Main Controls&quot;">​</a></h2><h3 id="applications-only" tabindex="-1">Applications Only <a class="header-anchor" href="#applications-only" aria-label="Permalink to &quot;Applications Only&quot;">​</a></h3><p>When enabled, WordPress behaves as application-first:</p><ul><li>unmatched core REST traffic is redirected according to your configured destination,</li><li>plugin routes can still be managed through route policy,</li><li>the setup is optimized for sites where WordPress is not the public front-end.</li></ul><h3 id="trusted-ips" tabindex="-1">Trusted IPs <a class="header-anchor" href="#trusted-ips" aria-label="Permalink to &quot;Trusted IPs&quot;">​</a></h3><p>Define known-safe IPs or CIDR ranges for operational access.</p><p>Use cases:</p><ul><li>secure admin maintenance access,</li><li>controlled bypass during incident response,</li><li>stable access for trusted infrastructure.</li></ul><h3 id="emergency-reset-token" tabindex="-1">Emergency Reset Token <a class="header-anchor" href="#emergency-reset-token" aria-label="Permalink to &quot;Emergency Reset Token&quot;">​</a></h3><p>Generate a one-time recovery token before enabling strict lockdown. If you lock yourself out, the token provides a controlled reset path.</p><p>Best practice:</p><ol><li>generate and store the token securely,</li><li>verify it once in staging,</li><li>rotate after use.</li></ol><hr><h2 id="safe-rollout-order" tabindex="-1">Safe Rollout Order <a class="header-anchor" href="#safe-rollout-order" aria-label="Permalink to &quot;Safe Rollout Order&quot;">​</a></h2><ol><li>Configure redirect destination in <a href="/theme/theme.html">Theme</a>.</li><li>Add trusted IPs for maintainers.</li><li>Generate emergency reset token and store it.</li><li>Enable applications only mode.</li><li>Validate public, app, and admin flows.</li></ol><hr><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="/applications/applications.html">Applications</a></li><li><a href="/routes/routes.html">Routes &amp; Exposure Control</a></li><li><a href="/global-ip-filtering/global-ip-filtering.html">Global IP Filtering</a></li><li><a href="/login-hardening/login-hardening.html">Auth Hardening</a></li></ul>',22)])])}const f=o(i,[["render",l]]);export{u as __pageData,f as default};
